import{_ as e,o as n,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"13. Examination Leave","description":"","frontmatter":{"title":"13. Examination Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave"]},"headers":[],"relativePath":"ebas/has-managers-admin/managers-admin/education-pd/13-examination-leave.md","filePath":"ebas/has-managers-admin/managers-admin/education-pd/13-examination-leave.md"}'),i={name:"ebas/has-managers-admin/managers-admin/education-pd/13-examination-leave.md"};function s(r,a,l,d,m,p){return n(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="_13-examination-leave" tabindex="-1">13. Examination Leave <a class="header-anchor" href="#_13-examination-leave" aria-label="Permalink to &quot;13. Examination Leave&quot;">​</a></h1><p>This clause only applies to Managers and Administrative Workers not employed by Royal Women’s Hospital or Royal Children’s Hospital.</p><p><strong>13.1</strong> An Employee will be granted leave on full pay in order to attend examinations necessary to obtain higher qualifications in such courses as are undertaken with the knowledge and approval of the Employer.</p><p><strong>13.2</strong> The amount of leave will be such as to allow the Employee to proceed to and from the place of examinations and in addition allow three clear working days other than a Saturday or a Sunday for pre-examination study if this is so desired.</p><p><strong>13.3</strong> Any leave granted under the provisions of this clause will be in addition to annual leave granted pursuant to clause 53 (Annual Leave).</p><p><strong>13.4</strong> Leave with pay granted under the provisions of this clause will not exceed six clear working days per year.</p><p>Plain language terms: exam leave.</p>',7)])])}const u=e(i,[["render",s]]);export{h as __pageData,u as default};
